CREATE EXTENSION IF NOT EXISTS postgis;
CREATE TABLE IF NOT EXISTS schema_migrations (id text PRIMARY KEY, applied_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS organizations (id uuid PRIMARY KEY, name text NOT NULL, slug text NOT NULL UNIQUE, timezone text NOT NULL DEFAULT 'UTC', settings jsonb NOT NULL DEFAULT '{}', created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS users (id uuid PRIMARY KEY, organization_id uuid NOT NULL REFERENCES organizations(id) ON DELETE RESTRICT, name text NOT NULL, email text NOT NULL UNIQUE, password_hash text NOT NULL, status text NOT NULL CHECK (status IN ('ACTIVE','INVITED','SUSPENDED')), created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS roles (id uuid PRIMARY KEY, organization_id uuid NOT NULL REFERENCES organizations(id) ON DELETE CASCADE, name text NOT NULL, system_role text NOT NULL CHECK (system_role IN ('ADMINISTRATOR','OPERATIONS_COORDINATOR','VIEWER')), created_at timestamptz NOT NULL DEFAULT now(), UNIQUE (organization_id, system_role));
CREATE TABLE IF NOT EXISTS user_roles (user_id uuid NOT NULL REFERENCES users(id) ON DELETE CASCADE, role_id uuid NOT NULL REFERENCES roles(id) ON DELETE CASCADE, PRIMARY KEY (user_id, role_id));
CREATE TABLE IF NOT EXISTS permissions (id uuid PRIMARY KEY, code text NOT NULL UNIQUE, description text NOT NULL);
CREATE TABLE IF NOT EXISTS role_permissions (role_id uuid NOT NULL REFERENCES roles(id) ON DELETE CASCADE, permission_id uuid NOT NULL REFERENCES permissions(id) ON DELETE CASCADE, PRIMARY KEY (role_id, permission_id));
CREATE TABLE IF NOT EXISTS audit_logs (id uuid PRIMARY KEY, organization_id uuid NOT NULL REFERENCES organizations(id) ON DELETE RESTRICT, user_id uuid REFERENCES users(id) ON DELETE SET NULL, action text NOT NULL, entity_type text NOT NULL, entity_id text NOT NULL, previous_value jsonb, new_value jsonb, reason text, ip_address text, correlation_id text, created_at timestamptz NOT NULL DEFAULT now());
CREATE INDEX IF NOT EXISTS audit_logs_organization_created_idx ON audit_logs (organization_id, created_at DESC);
CREATE INDEX IF NOT EXISTS users_organization_idx ON users (organization_id);
INSERT INTO permissions (id,code,description) VALUES ('00000000-0000-0000-0000-000000000001','organization:read','Read organization'),('00000000-0000-0000-0000-000000000002','organization:manage','Manage organization'),('00000000-0000-0000-0000-000000000003','user:read','Read users'),('00000000-0000-0000-0000-000000000004','user:manage','Manage users'),('00000000-0000-0000-0000-000000000005','audit:read','Read audit logs') ON CONFLICT DO NOTHING;
